      await fetch(`${DRIVE_API_BASE}/files/${existingId}`, {
        method: 'PATCH',
        headers: {
          Authorization: `Bearer ${token}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ name: BACKUP_FOLDER_NAME }),
      });
    }
    this.backupFolderId = existingId;
    return existingId;
  }
}

